package com.example.cameramaltiagent.agent;

import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.example.cameramaltiagent.model.AgentResult;
import com.example.cameramaltiagent.model.Product;
import com.example.cameramaltiagent.model.StyleAnalysis;
import com.example.cameramaltiagent.model.TryOnResult;

import java.io.File;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

/**
 * AgentPipeline — 4エージェントの順次オーケストレーター。
 *
 * 処理フロー:
 *   Step1: StyleAnalystAgent  (Gemini: テキスト → 構造化)
 *   Step2: ShoppingAgent      (Rakuten: 商品検索)
 *   Step3: TryOnAgent         (Replicate IDM-VTON: 試着画像生成)
 *   Step4: StylistAgent       (Gemini Multimodal: コメント生成)
 */
public class AgentPipeline {

    private static final String TAG = "AgentPipeline";

    /** ProcessingActivityからUIを更新するためのコールバック */
    public interface PipelineCallback {
        /** ステップ進捗通知 (step: 1〜4, message: 表示テキスト) */
        void onStepStarted(int step, String message);
        /** パイプライン完了 */
        void onComplete(AgentResult result);
        /** エラー発生 */
        void onError(String errorMessage);
    }

    private final ExecutorService executor = Executors.newSingleThreadExecutor();
    private final Handler mainHandler = new Handler(Looper.getMainLooper());

    private final StyleAnalystAgent styleAgent = new StyleAnalystAgent();
    private final ShoppingAgent shoppingAgent = new ShoppingAgent();
    private final TryOnAgent tryOnAgent = new TryOnAgent();
    private final StylistAgent stylistAgent = new StylistAgent();

    /**
     * パイプラインを開始する。バックグラウンドスレッドで実行される。
     *
     * @param selfieFile    Camera2で撮影・保存した自撮り画像ファイル
     * @param clothingText  ユーザーが入力した服装テキスト
     * @param callback      結果通知先（ActivityのUI更新に使用）
     */
    public void execute(File selfieFile, String clothingText, PipelineCallback callback) {
        executor.submit(() -> {
            AgentResult result = new AgentResult();
            try {
                // ── Step 1: StyleAnalystAgent ─────────────────────────
                notifyStep(callback, 1, " スタイルを解析中...");
                StyleAnalysis analysis = styleAgent.analyze(clothingText);
                result.styleAnalysis = analysis;
                Log.d(TAG, "Step1 done: " + analysis.searchQueryJa);

                // ── Step 2: ShoppingAgent ─────────────────────────────
                notifyStep(callback, 2, " 商品を検索中...");
                List<Product> products = shoppingAgent.search(analysis);
                result.products = products;
                Product selected = products.get(0); // 先頭商品を試着対象に選択
                result.selectedProduct = selected;
                Log.d(TAG, "Step2 done: " + selected.name);

                // ── Step 3: TryOnAgent (Gemini版) ────────────────────
                notifyStep(callback, 3, " AIが試着をシミュレーション中...\n(10〜15秒)");
                TryOnResult tryOn = tryOnAgent.execute(
                        selfieFile, selected, analysis.garmentDescForTryOn);
                result.tryOnResult = tryOn;

                if (!tryOn.success) {
                    String reason = (tryOn.failureReason != null && !tryOn.failureReason.isEmpty())
                            ? tryOn.failureReason
                            : "試着シミュレーションに失敗しました。再試行してください。";
                    throw new Exception(reason);
                }
                Log.d(TAG, "Step3 done in " + tryOn.durationMs + "ms");

                // ── Step 4: StylistAgent ──────────────────────────────
                notifyStep(callback, 4, "✨ スタイリングコメントを生成中...");
                String comment = stylistAgent.generateComment(
                        tryOn.outputImageUrl, tryOn.tryOnDescription, clothingText, selected.name);
                result.stylingComment = comment;
                Log.d(TAG, "Step4 done: " + comment.substring(0, Math.min(50, comment.length())));

                // ── 完了 ──────────────────────────────────────────────
                result.success = true;
                mainHandler.post(() -> callback.onComplete(result));

            } catch (Exception e) {
                Log.e(TAG, "Pipeline error", e);
                result.errorMessage = e.getMessage();
                mainHandler.post(() -> callback.onError(e.getMessage()));
            }
        });
    }

    /** UIスレッドへのステップ通知 */
    private void notifyStep(PipelineCallback callback, int step, String message) {
        mainHandler.post(() -> callback.onStepStarted(step, message));
    }

    public void shutdown() {
        executor.shutdownNow();
    }
}

package com.example.cameramaltiagent.agent;

import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.example.cameramaltiagent.model.AgentResult;
import com.example.cameramaltiagent.model.Product;
import com.example.cameramaltiagent.model.StyleAnalysis;
import com.example.cameramaltiagent.model.TryOnResult;

import java.io.File;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

/**
 * AgentPipeline — 4エージェントの順次オーケストレーター。
 * Step1: StyleAnalystAgent  (Gemini: テキスト→構造化)
 * Step2: ShoppingAgent      (Rakuten: 単品 or 複合並列検索)
 * Step3: TryOnAgent         (Gemini画像生成: 自撮り+コーデ説明→試着画像)
 * Step4: StylistAgent       (Gemini: スタイリングコメント)
 */
public class AgentPipeline {

    private static final String TAG = "AgentPipeline";

    /** ProcessingActivityからUIを更新するためのコールバック */
    public interface PipelineCallback {
        /** ステップ進捗通知 (step: 1〜4, message: 表示テキスト) */
        void onStepStarted(int step, String message);
        /** パイプライン完了 */
        void onComplete(AgentResult result);
        /** エラー発生 */
        void onError(String errorMessage);
    }

    private final ExecutorService executor = Executors.newSingleThreadExecutor();
    private final Handler mainHandler = new Handler(Looper.getMainLooper());

    private final StyleAnalystAgent styleAgent   = new StyleAnalystAgent();
    private final ShoppingAgent     shoppingAgent = new ShoppingAgent();
    private final TryOnAgent        tryOnAgent    = new TryOnAgent();
    private final StylistAgent      stylistAgent  = new StylistAgent();

    /**
     * パイプラインを開始する。バックグラウンドスレッドで実行される。
     *
     * @param selfieFile    Camera2で撮影・保存した自撮り画像ファイル
     * @param clothingText  ユーザーが入力した服装テキスト
     * @param callback      結果通知先（ActivityのUI更新に使用）
     */
    public void execute(File selfieFile, String clothingText, PipelineCallback callback) {
        executor.submit(() -> {
            AgentResult result = new AgentResult();
            try {
                // ── Step 1: StyleAnalystAgent ────────────────────────
                notifyStep(callback, 1, " スタイルを解析中...");
                StyleAnalysis analysis = styleAgent.analyze(clothingText);
                result.styleAnalysis = analysis;
                Log.d(TAG, "Step1 done: compound=" + analysis.isCompound
                        + " top=" + analysis.topSearchQueryJa
                        + " bottom=" + analysis.bottomSearchQueryJa);

                // ── Step 2: ShoppingAgent ────────────────────────────
                String shopMsg = analysis.isCompound
                        ? " 上着・下着を同時に検索中..."
                        : " 商品を検索中...";
                notifyStep(callback, 2, shopMsg);
                List<Product> products = shoppingAgent.search(analysis);
                result.products = products;

                Product topProduct    = products.get(0);
                Product bottomProduct = (products.size() >= 2) ? products.get(1) : null;
                result.selectedProduct = topProduct;
                result.bottomProduct   = bottomProduct;
                Log.d(TAG, "Step2 done: top=" + topProduct.name
                        + (bottomProduct != null ? " bottom=" + bottomProduct.name : ""));

                // ── Step 3: TryOnAgent ───────────────────────────────
                notifyStep(callback, 3, " AIが試着画像を生成中...\n(15〜30秒)");
                File outputDir = selfieFile.getParentFile();
                TryOnResult tryOn = tryOnAgent.execute(
                        selfieFile, topProduct, bottomProduct,
                        analysis.garmentDescForTryOn, outputDir);
                result.tryOnResult = tryOn;

                if (!tryOn.success) {
                    String reason = tryOn.failureReason != null
                            ? tryOn.failureReason : "試着画像の生成に失敗しました。";
                    throw new Exception(reason);
                }
                Log.d(TAG, "Step3 done in " + tryOn.durationMs + "ms isLocal=" + tryOn.isLocalFile);

                // ── Step 4: StylistAgent ─────────────────────────────
                notifyStep(callback, 4, "✨ スタイリングコメントを生成中...");
                String imageRef = tryOn.isLocalFile ? null : tryOn.outputImageUrl;
                String comment = stylistAgent.generateComment(
                        imageRef, tryOn.tryOnDescription, clothingText,
                        topProduct.name + (bottomProduct != null ? " + " + bottomProduct.name : ""));
                result.stylingComment = comment;

                result.success = true;
                mainHandler.post(() -> callback.onComplete(result));

            } catch (Exception e) {
                Log.e(TAG, "Pipeline error", e);
                result.errorMessage = e.getMessage();
                mainHandler.post(() -> callback.onError(e.getMessage()));
            }
        });
    }

    /** UIスレッドへのステップ通知 */
    private void notifyStep(PipelineCallback callback, int step, String message) {
        mainHandler.post(() -> callback.onStepStarted(step, message));
    }

    public void shutdown() {
        executor.shutdownNow();
    }
}

package com.example.cameramaltiagent.agent;

import com.example.cameramaltiagent.api.ShoppingApiClient;
import com.example.cameramaltiagent.model.Product;
import com.example.cameramaltiagent.model.StyleAnalysis;

import java.util.List;

/**
 * Agent 2: ShoppingAgent
 *
 * StyleAnalystAgent の出力（StyleAnalysis）を受け取り、
 * 楽天市場APIで国内商品を検索して購入リンク付きの商品リストを返す。
 */
public class ShoppingAgent {

    private final ShoppingApiClient shoppingApiClient;

    public ShoppingAgent() {
        this.shoppingApiClient = new ShoppingApiClient();
    }

    /**
     * 日本語クエリで楽天市場を検索して上位5件を返す。
     * クエリはStyleAnalystAgentが生成済みの searchQueryJa を使用。
     */
    public List<Product> search(StyleAnalysis analysis) throws Exception {
        String query = analysis.searchQueryJa;
        if (query == null || query.isEmpty()) {
            // フォールバック: 色 + 種類の最低限クエリ
            query = analysis.color + " " + analysis.garmentType;
        }
        List<Product> products = shoppingApiClient.searchProducts(query, 5);
        if (products.isEmpty()) {
            throw new Exception("ShoppingAgent: 商品が見つかりませんでした。クエリ: " + query);
        }
        return products;
    }
}

package com.example.cameramaltiagent.agent;

import android.util.Log;

import com.example.cameramaltiagent.api.ShoppingApiClient;
import com.example.cameramaltiagent.model.Product;
import com.example.cameramaltiagent.model.StyleAnalysis;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;

/**
 * Agent 2: ShoppingAgent
 *
 * 単品: リトライしながら1件検索
 * 複合コーデ: TOP/BOTTOMを並列検索して2件返す（index 0=TOP, 1=BOTTOM）
 */
public class ShoppingAgent {

    private static final String TAG = "ShoppingAgent";
    private final ShoppingApiClient api;

    public ShoppingAgent() {
        this.api = new ShoppingApiClient();
    }

    public List<Product> search(StyleAnalysis analysis) throws Exception {

        if (analysis.isCompound
                && analysis.topSearchQueryJa != null && !analysis.topSearchQueryJa.isEmpty()
                && analysis.bottomSearchQueryJa != null && !analysis.bottomSearchQueryJa.isEmpty()) {
            // ── 複合コーデ: 並列検索 ──────────────────────────────
            Log.d(TAG, "複合検索: TOP=" + analysis.topSearchQueryJa
                    + " BOTTOM=" + analysis.bottomSearchQueryJa);
            ExecutorService pool = Executors.newFixedThreadPool(2);
            Future<Product> topFuture    = pool.submit(() -> searchFirst(analysis.topSearchQueryJa));
            Future<Product> bottomFuture = pool.submit(() -> searchFirst(analysis.bottomSearchQueryJa));
            pool.shutdown();

            Product top    = topFuture.get();
            Product bottom = bottomFuture.get();

            List<Product> result = new ArrayList<>();
            if (top    != null) result.add(top);
            if (bottom != null) result.add(bottom);
            if (result.isEmpty()) throw new Exception("商品が見つかりませんでした。別のキーワードで再試行してください。");
            return result;
        }

        // ── 単品: リトライ付き検索 ────────────────────────────────
        String[] queries = {
                analysis.searchQueryJa,
                (analysis.color + " " + analysis.garmentType).trim(),
                analysis.garmentType
        };
        for (String q : queries) {
            if (q == null || q.isEmpty()) continue;
            Log.d(TAG, "単品検索: " + q);
            List<Product> r = api.searchProducts(q, 5);
            if (!r.isEmpty()) return r;
        }
        throw new Exception("商品が見つかりませんでした。\n別のキーワードで再試行してください。");
    }

    /** クエリで検索して最初の1件を返す（見つからなければnull） */
    private Product searchFirst(String query) {
        try {
            List<Product> r = api.searchProducts(query, 3);
            return r.isEmpty() ? null : r.get(0);
        } catch (Exception e) {
            Log.e(TAG, "searchFirst error: " + query, e);
            return null;
        }
    }
}

package com.example.cameramaltiagent.agent;

import com.example.cameramaltiagent.api.GeminiApiClient;
import com.example.cameramaltiagent.model.StyleAnalysis;

import org.json.JSONObject;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * Agent 1: StyleAnalystAgent
 *
 * ユーザーの自然言語テキスト（例：「茶色の半袖Tシャツとジーパン」）を
 * Gemini APIで構造化して StyleAnalysis オブジェクトに変換する。
 *
 * Gemini APIへのプロンプトでJSON形式の出力を強制し、
 * 正規表現フォールバックで安定したパースを保証する。
 */
public class StyleAnalystAgent {

    private final GeminiApiClient geminiClient;

    public StyleAnalystAgent() {
        this.geminiClient = new GeminiApiClient();
    }

    public StyleAnalysis analyze(String clothingText) throws Exception {
        String prompt = buildPrompt(clothingText);
        String rawResponse = geminiClient.generateText(prompt);
        return parseResponse(rawResponse);
    }

    private String buildPrompt(String clothingText) {
        return "以下の服装説明を解析し、必ずJSON形式のみで返してください。\n"
                + "JSON以外のテキストは絶対に含めないでください。\n\n"
                + "服装説明: 「" + clothingText + "」\n\n"
                + "返すべきJSON（このフォーマットで必ず返してください）:\n"
                + "{\n"
                + "  \"garment_type\": \"T-shirt\",\n"
                + "  \"color\": \"brown\",\n"
                + "  \"search_query_ja\": \"茶色 半袖 Tシャツ メンズ\",\n"
                + "  \"search_query_en\": \"brown short sleeve t-shirt\",\n"
                + "  \"garment_description_for_tryon\": \"brown short sleeve cotton t-shirt, casual style\",\n"
                + "  \"season\": \"summer\"\n"
                + "}";
    }

    /**
     * LLMの出力が不安定なことを想定した堅牢なJSON抽出処理。
     * 正規表現でJSONブロックのみを抜き出してパースする。
     */
    private StyleAnalysis parseResponse(String raw) throws Exception {
        // まずそのままパースを試みる
        String jsonStr = raw.trim();

        // JSON以外のテキストが混入した場合は正規表現で抽出
        if (!jsonStr.startsWith("{")) {
            Pattern p = Pattern.compile("\\{[^{}]*\\}", Pattern.DOTALL);
            Matcher m = p.matcher(jsonStr);
            if (m.find()) {
                jsonStr = m.group();
            } else {
                throw new Exception("StyleAnalystAgent: JSON抽出失敗。生レスポンス: " + raw);
            }
        }

        JSONObject json = new JSONObject(jsonStr);
        StyleAnalysis analysis = new StyleAnalysis();
        analysis.garmentType = json.optString("garment_type", "");
        analysis.color = json.optString("color", "");
        analysis.searchQueryJa = json.optString("search_query_ja", "");
        analysis.searchQueryEn = json.optString("search_query_en", "");
        analysis.garmentDescForTryOn = json.optString("garment_description_for_tryon", "");
        analysis.season = json.optString("season", "");
        return analysis;
    }
}

package com.example.cameramaltiagent.agent;

import com.example.cameramaltiagent.api.GeminiApiClient;
import com.example.cameramaltiagent.model.StyleAnalysis;

import org.json.JSONObject;

import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * Agent 1: StyleAnalystAgent
 *
 * ユーザーの自然言語テキスト（例：「茶色の半袖Tシャツとジーパン」）を
 * Gemini APIで構造化して StyleAnalysis オブジェクトに変換する。
 *
 * Gemini APIへのプロンプトでJSON形式の出力を強制し、
 * 正規表現フォールバックで安定したパースを保証する。
 */
public class StyleAnalystAgent {

    private final GeminiApiClient geminiClient;

    public StyleAnalystAgent() {
        this.geminiClient = new GeminiApiClient();
    }

    public StyleAnalysis analyze(String clothingText) throws Exception {
        String prompt = buildPrompt(clothingText);
        String rawResponse = geminiClient.generateText(prompt);
        return parseResponse(rawResponse);
    }

    private String buildPrompt(String clothingText) {
        return "以下の服装説明を解析し、必ずJSON形式のみで返してください。\n"
                + "JSON以外のテキストは絶対に含めないでください。\n\n"
                + "服装説明: 「" + clothingText + "」\n\n"
                + "【判定ルール】\n"
                + "- 上着（Tシャツ・シャツ・ジャケット等）と下着（パンツ・スカート等）の両方が含まれていれば is_compound=true\n"
                + "- top_search_query_ja: 上着だけの短い検索ワード（2〜3語）\n"
                + "- bottom_search_query_ja: 下着だけの短い検索ワード（2〜3語）\n"
                + "- search_query_ja: 単品の場合のみ使用（is_compound=falseのとき）\n"
                + "- garment_description_for_tryon: コーデ全体の詳細な英語説明\n\n"
                + "返すべきJSON:\n"
                + "{\n"
                + "  \"is_compound\": true,\n"
                + "  \"garment_type\": \"T-shirt\",\n"
                + "  \"color\": \"white\",\n"
                + "  \"search_query_ja\": \"白 オーバーサイズ Tシャツ\",\n"
                + "  \"top_search_query_ja\": \"白 オーバーサイズ Tシャツ\",\n"
                + "  \"bottom_search_query_ja\": \"黒 スキニーパンツ\",\n"
                + "  \"garment_description_for_tryon\": \"white oversized t-shirt and black skinny pants, casual street style\",\n"
                + "  \"season\": \"spring\"\n"
                + "}";
    }

    /**
     * LLMの出力が不安定なことを想定した堅牢なJSON抽出処理。
     * 正規表現でJSONブロックのみを抜き出してパースする。
     */
    private StyleAnalysis parseResponse(String raw) throws Exception {
        // まずそのままパースを試みる
        String jsonStr = raw.trim();

        // JSON以外のテキストが混入した場合は正規表現で抽出
        if (!jsonStr.startsWith("{")) {
            Pattern p = Pattern.compile("\\{[^{}]*\\}", Pattern.DOTALL);
            Matcher m = p.matcher(jsonStr);
            if (m.find()) {
                jsonStr = m.group();
            } else {
                throw new Exception("StyleAnalystAgent: JSON抽出失敗。生レスポンス: " + raw);
            }
        }

        JSONObject json = new JSONObject(jsonStr);
        StyleAnalysis analysis = new StyleAnalysis();
        analysis.garmentType          = json.optString("garment_type", "");
        analysis.color                = json.optString("color", "");
        analysis.searchQueryJa        = json.optString("search_query_ja", "");
        analysis.searchQueryEn        = json.optString("search_query_en", "");
        analysis.garmentDescForTryOn  = json.optString("garment_description_for_tryon", "");
        analysis.season               = json.optString("season", "");
        analysis.isCompound           = json.optBoolean("is_compound", false);
        analysis.topSearchQueryJa     = json.optString("top_search_query_ja", "");
        analysis.bottomSearchQueryJa  = json.optString("bottom_search_query_ja", "");
        return analysis;
    }
}

package com.example.cameramaltiagent.agent;

import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.util.Log;

import com.example.cameramaltiagent.api.GeminiApiClient;
import com.example.cameramaltiagent.model.Product;
import com.example.cameramaltiagent.model.TryOnResult;

import java.io.ByteArrayOutputStream;
import java.io.File;

/**
 * Agent 3: TryOnAgent（Gemini版）
 *
 * 自撮り画像をGeminiに送り「この人がこの服を着たらどう見えるか」を
 * テキストで描写させる。商品画像（楽天URL）を表示用として使用。
 *
 * ※ Replicateは起動5分以上かかるため廃止。Geminiなら10〜15秒で完了。
 */
public class TryOnAgent {

    private static final String TAG = "TryOnAgent";
    private final GeminiApiClient geminiClient;

    public TryOnAgent() {
        this.geminiClient = new GeminiApiClient();
    }

    public TryOnResult execute(File selfieFile, Product product, String garmentDesc)
            throws Exception {
        long startTime = System.currentTimeMillis();
        try {
            // 自撮り画像をリサイズしてバイト列に変換
            Bitmap selfie = loadAndResize(selfieFile, 768);
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            selfie.compress(Bitmap.CompressFormat.JPEG, 80, baos);
            byte[] selfieBytes = baos.toByteArray();

            // Geminiに試着描写を依頼
            String prompt = buildTryOnPrompt(garmentDesc, product.name);
            String description = geminiClient.generateWithBase64Image(prompt, selfieBytes);

            long duration = System.currentTimeMillis() - startTime;
            Log.d(TAG, "TryOn Gemini done in " + duration + "ms");

            // 商品画像URLを表示用に、Geminiの描写をテキスト結果として返す
            return new TryOnResult(product.imageUrl, description, duration);

        } catch (Exception e) {
            Log.e(TAG, "TryOn failed", e);
            return TryOnResult.failure(e.getMessage());
        }
    }

    private String buildTryOnPrompt(String garmentDesc, String productName) {
        return "あなたはAIファッションアシスタントです。\n"
                + "この画像の人物が、次の商品を試着したとき、どのように見えるか詳しく描写してください。\n\n"
                + "試着する商品: 「" + productName + "」\n"
                + "服の特徴: " + garmentDesc + "\n\n"
                + "以下の観点で150字程度で描写してください:\n"
                + "・この人物の体型・雰囲気にその服がどう合うか\n"
                + "・全体的なシルエットと印象\n"
                + "・カラーバランスと全体の調和\n\n"
                + "まるで実際に試着を目の前で見ているように、自然な日本語で描写してください。";
    }

    private Bitmap loadAndResize(File file, int maxSide) {
        BitmapFactory.Options opts = new BitmapFactory.Options();
        opts.inJustDecodeBounds = true;
        BitmapFactory.decodeFile(file.getAbsolutePath(), opts);
        int sampleSize = 1;
        while (opts.outWidth / sampleSize > maxSide
                || opts.outHeight / sampleSize > maxSide) {
            sampleSize *= 2;
        }
        opts.inSampleSize = sampleSize;
        opts.inJustDecodeBounds = false;
        return BitmapFactory.decodeFile(file.getAbsolutePath(), opts);
    }
}

package com.example.cameramaltiagent.agent;

import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.util.Log;

import com.example.cameramaltiagent.api.GeminiApiClient;
import com.example.cameramaltiagent.model.Product;
import com.example.cameramaltiagent.model.TryOnResult;

import java.io.ByteArrayOutputStream;
import java.io.File;
import java.io.FileOutputStream;

/**
 * Agent 3: TryOnAgent（Gemini画像生成版）
 *
 * 自撮り写真をbase64でGeminiに送り
 * 「この人物に服を着せた画像を生成」させる。
 * 生成画像はローカルファイルに保存し、パスをTryOnResultに格納する。
 */
public class TryOnAgent {

    private static final String TAG = "TryOnAgent";
    private final GeminiApiClient geminiClient;

    public TryOnAgent() {
        this.geminiClient = new GeminiApiClient();
    }

    /**
     * @param selfieFile     自撮り画像ファイル
     * @param topProduct     上着商品（単品の場合はこれだけ）
     * @param bottomProduct  下着商品（単品の場合はnull）
     * @param garmentDesc    コーデ全体の英語説明
     * @param outputDir      生成画像の保存先ディレクトリ
     */
    public TryOnResult execute(File selfieFile, Product topProduct, Product bottomProduct,
                               String garmentDesc, File outputDir) throws Exception {
        long startTime = System.currentTimeMillis();
        try {
            // 自撮りをリサイズしてバイト列に変換
            Bitmap selfie = loadAndResize(selfieFile, 768);
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            selfie.compress(Bitmap.CompressFormat.JPEG, 80, baos);
            byte[] selfieBytes = baos.toByteArray();

            // プロンプト組み立て
            String prompt = buildPrompt(topProduct, bottomProduct, garmentDesc);
            Log.d(TAG, "TryOn prompt: " + prompt);

            // Gemini 画像生成
            byte[] imageBytes = geminiClient.generateTryOnImage(prompt, selfieBytes);
            long duration = System.currentTimeMillis() - startTime;

            if (imageBytes == null) {
                // 画像生成失敗→テキスト描写にフォールバック
                Log.w(TAG, "Gemini画像生成失敗。テキスト描写にフォールバック");
                String desc = geminiClient.generateWithBase64Image(
                        buildTextPrompt(topProduct, bottomProduct, garmentDesc), selfieBytes);
                TryOnResult result = new TryOnResult(
                        topProduct != null ? topProduct.imageUrl : null, desc, duration);
                return result;
            }

            // 生成画像をファイル保存
            File outFile = new File(outputDir, "tryon_result.png");
            try (FileOutputStream fos = new FileOutputStream(outFile)) {
                fos.write(imageBytes);
            }
            Log.d(TAG, "TryOn image saved: " + outFile.getAbsolutePath() + " (" + duration + "ms)");

            TryOnResult result = new TryOnResult(outFile.getAbsolutePath(), null, duration);
            result.isLocalFile = true;
            return result;

        } catch (Exception e) {
            Log.e(TAG, "TryOn failed", e);
            return TryOnResult.failure(e.getMessage());
        }
    }

    private String buildPrompt(Product top, Product bottom, String garmentDesc) {
        StringBuilder sb = new StringBuilder();
        sb.append("あなたはプロのファッションデザイナーです。\n");
        sb.append("この写真の人物に、以下の服を実際に着せた自然なファッション写真を生成してください。\n\n");
        if (top != null) sb.append("【上着】").append(top.name).append("\n");
        if (bottom != null) sb.append("【下着】").append(bottom.name).append("\n");
        sb.append("【コーデ説明】").append(garmentDesc).append("\n\n");
        sb.append("・人物の顔・体型・ポーズはそのままにしてください\n");
        sb.append("・服だけを自然に合成してください\n");
        sb.append("・プロのファッション雑誌のような仕上がりにしてください");
        return sb.toString();
    }

    private String buildTextPrompt(Product top, Product bottom, String garmentDesc) {
        return "あなたはAIファッションアシスタントです。\n"
                + "この画像の人物が次のコーデを着たとき、どのように見えるか詳しく描写してください。\n\n"
                + (top != null ? "上着: " + top.name + "\n" : "")
                + (bottom != null ? "下着: " + bottom.name + "\n" : "")
                + "コーデ説明: " + garmentDesc + "\n\n"
                + "150字程度で、シルエット・カラーバランス・全体の印象を自然な日本語で描写してください。";
    }

    private Bitmap loadAndResize(File file, int maxSide) {
        BitmapFactory.Options opts = new BitmapFactory.Options();
        opts.inJustDecodeBounds = true;
        BitmapFactory.decodeFile(file.getAbsolutePath(), opts);
        int sampleSize = 1;
        while (opts.outWidth / sampleSize > maxSide || opts.outHeight / sampleSize > maxSide) {
            sampleSize *= 2;
        }
        opts.inSampleSize = sampleSize;
        opts.inJustDecodeBounds = false;
        return BitmapFactory.decodeFile(file.getAbsolutePath(), opts);
    }
}

package com.example.cameramaltiagent.api;

import android.util.Base64;

import com.example.cameramaltiagent.BuildConfig;

import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import okhttp3.MediaType;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

/**
 * Gemini 1.5 Flash APIクライアント。
 * テキストのみ・マルチモーダル（画像URL + テキスト）の両方に対応。
 */
public class GeminiApiClient {

    private static final String BASE_URL =
            "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent";
    private static final MediaType JSON = MediaType.get("application/json; charset=utf-8");

    private final OkHttpClient client;
    private final String apiKey;

    public GeminiApiClient() {
        this.apiKey = BuildConfig.GEMINI_API_KEY;
        this.client = new OkHttpClient.Builder()
                .connectTimeout(30, TimeUnit.SECONDS)
                .readTimeout(60, TimeUnit.SECONDS)
                .build();
    }

    /**
     * テキストのみのプロンプトを送信。
     * StyleAnalystAgent / StylistAgent（テキスト部分）で使用。
     */
    public String generateText(String prompt) throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();
        JSONObject part = new JSONObject();
        part.put("text", prompt);
        parts.put(part);
        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        return executeRequest(body);
    }

    /**
     * 画像URL + テキストのマルチモーダルプロンプトを送信。
     * StylistAgentで試着結果画像を解析するときに使用。
     */
    public String generateWithImageUrl(String prompt, String imageUrl) throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();

        // 画像パート（URL指定）
        JSONObject imagePart = new JSONObject();
        JSONObject fileData = new JSONObject();
        fileData.put("mimeType", "image/jpeg");
        fileData.put("fileUri", imageUrl);
        imagePart.put("fileData", fileData);
        parts.put(imagePart);

        // テキストパート
        JSONObject textPart = new JSONObject();
        textPart.put("text", prompt);
        parts.put(textPart);

        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        return executeRequest(body);
    }

    /**
     * ローカル画像（バイト列）をbase64でインライン送信するプロンプト。
     * TryOnAgentで自撮り画像を解析するときに使用。
     */
    public String generateWithBase64Image(String prompt, byte[] imageBytes)
            throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();

        // インライン画像パート（base64）
        JSONObject imagePart = new JSONObject();
        JSONObject inlineData = new JSONObject();
        inlineData.put("mimeType", "image/jpeg");
        inlineData.put("data", Base64.encodeToString(imageBytes, Base64.NO_WRAP));
        imagePart.put("inlineData", inlineData);
        parts.put(imagePart);

        // テキストパート
        JSONObject textPart = new JSONObject();
        textPart.put("text", prompt);
        parts.put(textPart);

        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        return executeRequest(body);
    }

    private String executeRequest(JSONObject body) throws IOException, JSONException {
        String url = BASE_URL + "?key=" + apiKey;
        RequestBody reqBody = RequestBody.create(body.toString(), JSON);
        Request request = new Request.Builder()
                .url(url)
                .post(reqBody)
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful() || response.body() == null) {
                throw new IOException("Gemini API error: " + response.code()
                        + " " + (response.body() != null ? response.body().string() : ""));
            }
            String responseStr = response.body().string();
            JSONObject json = new JSONObject(responseStr);
            return json.getJSONArray("candidates")
                    .getJSONObject(0)
                    .getJSONObject("content")
                    .getJSONArray("parts")
                    .getJSONObject(0)
                    .getString("text");
        }
    }
}

package com.example.cameramaltiagent.api;

import android.util.Base64;

import com.example.cameramaltiagent.BuildConfig;

import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import okhttp3.MediaType;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

/**
 * Gemini 1.5 Flash APIクライアント。
 * テキストのみ・マルチモーダル（画像URL + テキスト）の両方に対応。
 */
public class GeminiApiClient {

    private static final String BASE_URL =
            "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent";
    private static final String IMAGE_GEN_URL =
            "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image:generateContent";
    private static final MediaType JSON = MediaType.get("application/json; charset=utf-8");

    private final OkHttpClient client;
    private final String apiKey;

    public GeminiApiClient() {
        this.apiKey = BuildConfig.GEMINI_API_KEY;
        this.client = new OkHttpClient.Builder()
                .connectTimeout(30, TimeUnit.SECONDS)
                .readTimeout(120, TimeUnit.SECONDS)
                .writeTimeout(60, TimeUnit.SECONDS)
                .build();
    }

    /**
     * テキストのみのプロンプトを送信。
     * StyleAnalystAgent / StylistAgent（テキスト部分）で使用。
     */
    public String generateText(String prompt) throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();
        JSONObject part = new JSONObject();
        part.put("text", prompt);
        parts.put(part);
        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        return executeRequest(body);
    }

    /**
     * 画像URL + テキストのマルチモーダルプロンプトを送信。
     * StylistAgentで試着結果画像を解析するときに使用。
     */
    public String generateWithImageUrl(String prompt, String imageUrl) throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();

        // 画像パート（URL指定）
        JSONObject imagePart = new JSONObject();
        JSONObject fileData = new JSONObject();
        fileData.put("mimeType", "image/jpeg");
        fileData.put("fileUri", imageUrl);
        imagePart.put("fileData", fileData);
        parts.put(imagePart);

        // テキストパート
        JSONObject textPart = new JSONObject();
        textPart.put("text", prompt);
        parts.put(textPart);

        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        return executeRequest(body);
    }

    /**
     * ローカル画像（バイト列）をbase64でインライン送信するプロンプト。
     * TryOnAgentで自撮り画像を解析するときに使用。
     */
    public String generateWithBase64Image(String prompt, byte[] imageBytes)
            throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();

        // インライン画像パート（base64）
        JSONObject imagePart = new JSONObject();
        JSONObject inlineData = new JSONObject();
        inlineData.put("mimeType", "image/jpeg");
        inlineData.put("data", Base64.encodeToString(imageBytes, Base64.NO_WRAP));
        imagePart.put("inlineData", inlineData);
        parts.put(imagePart);

        // テキストパート
        JSONObject textPart = new JSONObject();
        textPart.put("text", prompt);
        parts.put(textPart);

        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        return executeRequest(body);
    }

    /**
     * テキストのみで画像生成（人物写真なし）。
     * TryOnAgentのStep2で使用。ポリシー問題を回避するため実写真を渡さない。
     * モデル: gemini-2.5-flash-image
     *
     * @return PNG画像のバイト列（失敗時はnull）
     */
    public byte[] generateImageFromText(String prompt) throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();

        JSONObject textPart = new JSONObject();
        textPart.put("text", prompt);
        parts.put(textPart);

        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        JSONObject genConfig = new JSONObject();
        JSONArray modalities = new JSONArray();
        modalities.put("IMAGE");
        modalities.put("TEXT");
        genConfig.put("responseModalities", modalities);
        body.put("generationConfig", genConfig);

        String url = IMAGE_GEN_URL + "?key=" + apiKey;
        RequestBody reqBody = RequestBody.create(body.toString(), JSON);
        Request request = new Request.Builder()
                .url(url)
                .post(reqBody)
                .build();

        try (Response response = client.newCall(request).execute()) {
            String responseBody = response.body() != null ? response.body().string() : "";
            if (!response.isSuccessful()) {
                throw new IOException("Gemini ImageGen error: " + response.code() + " " + responseBody);
            }
            JSONObject json = new JSONObject(responseBody);
            JSONArray responseParts = json.getJSONArray("candidates")
                    .getJSONObject(0)
                    .getJSONObject("content")
                    .getJSONArray("parts");
            for (int i = 0; i < responseParts.length(); i++) {
                JSONObject part = responseParts.getJSONObject(i);
                if (part.has("inlineData")) {
                    String b64 = part.getJSONObject("inlineData").getString("data");
                    return Base64.decode(b64, Base64.NO_WRAP);
                }
            }
            return null;
        }
    }

    /**
     * @deprecated Step2方式（generateImageFromText）を使用してください
     */
    public byte[] generateTryOnImage(String prompt, byte[] selfieBytes)
            throws IOException, JSONException {
        JSONObject body = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();

        // 自撮りをbase64インラインで送信
        JSONObject imagePart = new JSONObject();
        JSONObject inlineData = new JSONObject();
        inlineData.put("mimeType", "image/jpeg");
        inlineData.put("data", Base64.encodeToString(selfieBytes, Base64.NO_WRAP));
        imagePart.put("inlineData", inlineData);
        parts.put(imagePart);

        // テキストプロンプト
        JSONObject textPart = new JSONObject();
        textPart.put("text", prompt);
        parts.put(textPart);

        content.put("parts", parts);
        content.put("role", "user");
        contents.put(content);
        body.put("contents", contents);

        // IMAGE出力を要求
        JSONObject genConfig = new JSONObject();
        JSONArray modalities = new JSONArray();
        modalities.put("IMAGE");
        modalities.put("TEXT");
        genConfig.put("responseModalities", modalities);
        body.put("generationConfig", genConfig);

        String url = IMAGE_GEN_URL + "?key=" + apiKey;
        RequestBody reqBody = RequestBody.create(body.toString(), JSON);
        Request request = new Request.Builder()
                .url(url)
                .post(reqBody)
                .build();

        try (Response response = client.newCall(request).execute()) {
            String responseBody = response.body() != null ? response.body().string() : "";
            if (!response.isSuccessful()) {
                throw new IOException("Gemini ImageGen error: " + response.code() + " " + responseBody);
            }
            JSONObject json = new JSONObject(responseBody);
            JSONArray responseParts = json.getJSONArray("candidates")
                    .getJSONObject(0)
                    .getJSONObject("content")
                    .getJSONArray("parts");

            // parts の中からinlineData（画像）を探す
            for (int i = 0; i < responseParts.length(); i++) {
                JSONObject part = responseParts.getJSONObject(i);
                if (part.has("inlineData")) {
                    String b64 = part.getJSONObject("inlineData").getString("data");
                    return Base64.decode(b64, Base64.NO_WRAP);
                }
            }
            return null; // 画像パートなし
        }
    }

    private String executeRequest(JSONObject body) throws IOException, JSONException {
        String url = BASE_URL + "?key=" + apiKey;
        RequestBody reqBody = RequestBody.create(body.toString(), JSON);
        Request request = new Request.Builder()
                .url(url)
                .post(reqBody)
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful() || response.body() == null) {
                throw new IOException("Gemini API error: " + response.code()
                        + " " + (response.body() != null ? response.body().string() : ""));
            }
            String responseStr = response.body().string();
            JSONObject json = new JSONObject(responseStr);
            return json.getJSONArray("candidates")
                    .getJSONObject(0)
                    .getJSONObject("content")
                    .getJSONArray("parts")
                    .getJSONObject(0)
                    .getString("text");
        }
    }
}

